            return String.fromCharCode(aCharCode + mirrorPos);
        } else if (char >= '0' && char <= '9') {
            // Digit mapping: 0 <-> 9, 1 <-> 8, etc.
            const digitVal = parseInt(char);
            // Mirror value: 9 - digitVal
            const mirrorVal = 9 - digitVal;
            return String.fromCharCode('0'.charCodeAt(0) + mirrorVal);
