function solve(s) {
    // 1. Frequency Counting
    const freq = new Map();
    for (const char of s) {
        freq.set(char, (freq.get(char) || 0) + 1);
    }

    /**
     * Calculates the mirror character of a given character.
     * @param {string} char 
     * @returns {string} The mirror character.
     */
    function getMirrorChar(char) {
        const code = char.charCodeAt(0);

        // Check if it's a lowercase letter ('a' = 97, 'z' = 122)
        if (code >= 97 && code <= 122) {
            // a maps to z, b maps to y, etc.
            // Sum of start and end codes: 97 + 122 = 219
            // New code = 219 - current code
            return String.fromCharCode(97 + 122 - code);
        } 
        // Check if it's a digit ('0' = 48, '9' = 57)
        else if (code >= 48 && code <= 57) {
            // 0 maps to 9, 1 maps to 8, etc.
            // Sum of start and end codes: 48 + 57 = 105
            // New code = 105 - current code
            return String.fromCharCode(48 + 57 - code);
        }
        // Should not happen based on problem constraints
        return char;
    }

    let totalDiffSum = 0;
    const processedPairs = new Set();

    // 3. Iterating and Calculating Sum
    for (const charC of freq.keys()) {
        const m = getMirrorChar(charC);

        // Use a canonical representation for the pair to ensure we only process it once.
        // We enforce that we only calculate the contribution if charC is lexicographically 
        // less than or equal to m, or if it's the first time we see this specific pair.

        // Using a set ensures we only process (c, m) or (m, c) once.
        const pairKey = charC < m ? charC + m : m + charC;

        if (processedPairs.has(pairKey)) {
            continue;
        }
        processedPairs.add(pairKey);

        const freqC = freq.get(charC);

        // freq(m) is 0 if m is not in the string
        const freqM = freq.get(m) || 0;

        // Calculate the absolute difference
        const difference = Math.abs(freqC - freqM);

        totalDiffSum += difference;
    }

    return totalDiffSum;
}
